const e=JSON.parse('{"key":"v-63f179f0","path":"/complain_diary/2024_06_17.html","title":"我的前端之路(一)","lang":"zh-CN","frontmatter":{"article":false,"title":"我的前端之路(一)","icon":"face-meh-blank"},"headers":[],"git":{"createdTime":1718558840000,"updatedTime":1718558840000,"contributors":[{"name":"Jeacson_Snake","email":"Jeacson_Snake@outlook.com","commits":1}]},"readingTime":{"minutes":4.31,"words":1292},"filePathRelative":"complain_diary/2024_06_17.md","localizedDate":"2024年6月16日","excerpt":"<p>从2023年底至今已经太久没有在博客上进行更新了，甚至连前端的知识都忘了不少。</p>\\n<p>自从4月30号毕业设计的答辩结束之后，我已经在宿舍里无所事事了将近一个半月。原本想着说趁着这几个月赶快休整下调整自己的睡眠时长，结果直到现在为止依然改不了晚睡的老毛病。</p>\\n<p>怎么说呢，人生本来就是一阶段一阶段走的，我在大学的前面几年懵懂无知，中间几年因为过于不自信、自暴自弃丧失了很多机会，于是便落到了这般境地。倒不如说现在依然在处于自暴自弃的状态，不过更多的是不会有更加剧烈的反应了，就像投入了石子的池塘，随着时间流逝，水面也慢慢的平静下来。</p>\\n<p>在迷茫的这几年里我想了很多，因为前端这条路本质上只是因为在大一的下学期，为了在项目课上做出些成果，所以自学了前端，和组员们一起写了个天气地图的网站项目出来。我现在还记得当时的导师说我们“作为自动化偏硬件的学生却选择了一个纯软件的项目”，而选择这个项目的一大部分原因，也只是因为当时碰巧挑到了这个没有人选的课题。我那时还只是很粗略的学了下前端，发现还挺好玩的，于是我们用LNMP，就是“Linux/Nginx/MySQL/PHP”的经典网络前后端组合架构，用十几年前的技术栈硬是撮了一个理论上可以放到树莓派上运行的天气地图查询网站。当时的我们甚至不知道如何调用已有的天气查询网站的API，而即使那时使用这些API也需要进行相应的收费，于是我们这些“不想费事”的大学生就用了更费劲的方法——用python爬虫从天气网站上爬取了能见到的数据下来放进数据库，然后再用PHP直接call的MySQL。现在回想起来，这都不算是一个放得上台面的项目，不过那个项目我们还是拿到了满绩。</p>"}');export{e as data};
